var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……그러니까 당신이 먼저 우리 회사에 연락을 취했다고?","JPN":"……つまり、あなたのほうからうちの会社に連絡をとったってこと？","ENG":"...So you were the one who contacted our company first?","TWN":"……所以是你先聯絡了我們公司嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"의외네. 구 관리국 출신이라고 하길래, 당연히 부사장님이 먼저 접촉했을 줄 알았는데.","JPN":"意外だね。旧管理局出身というから、当然副社長から持ちかけた話かなと思ってた。","ENG":"That's unexpected. I figured the Vice President approached you, since you're from the Old Administration.","TWN":"真意外。聽說是舊管理局出身的，我還以為副總會先接觸呢。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"내가 동결 조치에서 깨어난 건, 불과 얼마 전의 일이다.","JPN":"私が凍結から解放されたのはつい最近のことだ。","ENG":"I only woke from cryogenic stasis not long ago.","TWN":"我從凍結狀態中醒來，是不久前的事。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"아샤와의 우연한 만남을 통해, 비로소 눈을 뜰 수 있게 되었지.","JPN":"偶然アーシャと出会い、新たに目覚めることができた。","ENG":"It was a chance encounter with Asha that... opened my eyes.","TWN":"透過與阿莎的偶遇，我終於能夠睜開眼睛了。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"자, 잠깐! 수리야 님……!","JPN":"ちょっと、スーリヤさん……！","ENG":"W-wait! Surya...!","TWN":"等，等等！蘇莉耶……！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그런 식으로 말하면, 꼭 이상한 취향에 눈을 뜬 것 같잖아요!","JPN":"その言い方だと、何か変な趣味に目覚めたみたいじゃないですか！","ENG":"The way you said that makes it sound like you... opened your eyes to some strange taste or something!","TWN":"這麼說的話，好像我覺醒了什麼奇怪的癖好一樣！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"이상한 취향? 무슨 취향을 말하는 거지?","JPN":"変な趣味？　何のことだ？","ENG":"Strange taste? What are you talking about?","TWN":"奇怪的癖好？你在說什麼癖好？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그, 그게 그러니까……! 몰라! 그런 게 있다고요!","JPN":"そ、その、だから……！　もう、知りません！","ENG":"I-I don't know! Just... you know what I mean!","TWN":"那，那個其實……！不知道！反正有那麼回事！"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"아무튼 아샤와 만나지 못했다면, 나는 여전히 동결되어 있었겠지.","JPN":"とにかく、アーシャとの出会いがなかったら、私はいまだに凍結状態にあっただろう。","ENG":"Anyway, if I hadn't met Asha, I'd still be in cryogenic stasis.","TWN":"總之，如果沒有遇到阿莎，我可能還會被冰封著。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그리고 어쩌면 나와 마찬가지로 동결 조치를 받은 전대원들이 더 있을지도 몰라.","JPN":"それに、私と同じく凍結措置された戦隊員が他にもいる可能性がある。","ENG":"And it's possible there are other division members like me who were also put into cryogenic stasis.","TWN":"而且可能還有和我一樣被凍結的前隊員。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"관리실패로 인해, 최고 관리자도 모든 전대원들의 생사를 파악하지는 못한 모양이니까.","JPN":"管理失敗により、最高管理者も隊員全員の生死は把握できなかったようだしな。","ENG":"With the way things were mismanaged, even the Supreme Administrator seems to have lost track of who's still alive.","TWN":"由於管理失敗，最高管理者也無法掌握所有隊員的生死情況。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 사장님한테 당신이 깨어났다는 걸 알리려고 연락한 거야?","JPN":"じゃあ、社長にあなたが目覚めたことを知らせるために連絡してきたってこと？","ENG":"So... did you contact Boss to let him know you've woken up?","TWN":"那麼，是聯絡老闆告訴他你醒了嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그렇지는 않아. 나 역시 당분간 내 신분을 드러낼 생각이 없었거든.","JPN":"そうではない。当分の間、身分を明かすつもりはなかった。","ENG":"No, I didn't. I had no intention of revealing myself, at least not for a while.","TWN":"並不是這樣。我也不打算在短時間內暴露我的身份。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"しかし……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"저 하늘에 떠있는 우주선을 보니 생각이 달라지더군.","JPN":"あの空に浮かぶ宇宙船を見て、考えを改めた。","ENG":"After seeing that spaceship hovering up in the sky, I changed my mind.","TWN":"看到那天空中的太空船，我的想法改變了。"},"stage":{"bg":"MS_1407","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"저걸 이대로 방치했다간, 틀림없이 <color=#ffd34c>바루나스트라</color> 때와 같은 참사가 일어날 거다.","JPN":"あれをこのまま放置したら、間違いなく<color=#ffd34c>ヴァルナストラ</color>の時と同じ惨事が起こるだろう。","ENG":"If we leave it alone, there's no doubt we'll see a disaster just like what happened with <color=#ffd34c>Varunastra</color>.","TWN":"如果就那樣放任不管，肯定會發生和<color=#ffd34c>伐樓拿之艦</color>一樣的慘劇。"},"stage":{"bg":"MS_1407","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"바루나스트라라고? 그게 뭔데?","JPN":"ヴァルナストラ？　何それ？","ENG":"Varunastra? What's that?","TWN":"伐樓拿之艦？那是什麼？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"바루나스트라는 정보 말소를 유발하는 침식체다.","JPN":"ヴァルナストラは情報抹消を誘発する侵食体だ。","ENG":"Varunastra is a C.O. that causes information erasure.","TWN":"伐樓拿之艦是引發資訊抹消的侵蝕體。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 정보 말소라고……?","JPN":"まって、情報抹消……？","ENG":"Wait... did you say information erasure...?","TWN":"等等，資訊抹消……？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그래. 녀석은 오래전부터 로터스에 떠돌며 모래 폭풍을 일으키는 존재로 알려져 있었지.","JPN":"ああ。やつは古くからロータスを彷徨い、砂嵐を起こす存在として知られている。","ENG":"Yeah. It's been drifting over Lotus for years, known for stirring up sandstorms.","TWN":"是啊。那傢伙很久以前就被認為是在洛德斯遊盪並引發沙塵暴的存在。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"하지만 녀석의 실체는 클리파 허수 에너지의 간섭으로 인해, 의식을 얻게 된 5종 침식체.","JPN":"しかしやつの正体は、クリファ虚数エネルギーの干渉によって自我を手に入れた第5種侵食体。","ENG":"But in truth, it's a Category 5 C.O. that gained consciousness through interference from Qlipha Imaginary Energy.","TWN":"但是那傢伙的實體由於逆卡巴拉虛空能量的干擾，獲得了意識，變成了5類侵蝕體。"},"stage":{"bg":"VARUNA_04_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"따라서 녀석에게 삼켜진 존재는 정보 자체가 말소되어 모두에게서 잊혀 버려.","JPN":"やつに飲み込まれた存在は情報ごと抹消され、皆から忘れられてしまう。","ENG":"Anyone it devours... their information is erased. No one remembers them.","TWN":"因此，被它吞噬的存在會被抹消資訊，被所有人遺忘。"},"stage":{"bg":"VARUNA_04_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"20년 전, 대환류 사건에 휘말린 우리 전대원들은 나를 제외한 전원이 정보 말소를 당했다.","JPN":"20年前の大還流事件に巻き込まれた私の戦隊は、私を除く全員が情報抹消された。","ENG":"Twenty years ago, during the Great Gyre incident, every member of our division except me was affected by information erasure.","TWN":"20年前，捲入大環流事件的全隊成員，除了我以外，全部被抹消了資訊。"},"stage":{"bg":"VARUNA_04_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그로부터 20년이 지나버린 뒤…….","JPN":"あれから20年が経ち……","ENG":"And after those twenty years had passed...","TWN":"那之後已經過了20年……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};